const WebSocket = require('ws');

const PORT = process.env.PORT || 8080;
const TICK_RATE = 20;
const TICK_MS = 1000 / TICK_RATE;

const wss = new WebSocket.Server({ port: PORT });

let nextPlayerId = 1;
let nextUnitId = 1;
let nextBuildingId = 1;

const game = {
  players: new Map(),
  units: new Map(),
  buildings: new Map(),
  projectiles: new Map(),
  startedAt: Date.now(),
};

function randomInRange(min, max) {
  return Math.random() * (max - min) + min;
}

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function distance(a, b) {
  const dx = a.x - b.x;
  const dy = a.y - b.y;
  return Math.sqrt(dx * dx + dy * dy);
}

function createPlayer(ws) {
  const id = String(nextPlayerId++);
  const player = {
    id,
    ws,
    resources: 500,
    color: `hsl(${Math.floor(Math.random() * 360)}, 80%, 60%)`,
    name: `Player ${id}`,
    connected: true,
    lastSeen: Date.now(),
  };
  game.players.set(id, player);

  const baseX = randomInRange(100, 700);
  const baseY = randomInRange(100, 500);

  const townHall = createBuilding({
    playerId: id,
    type: 'townhall',
    x: baseX,
    y: baseY,
    hp: 1500,
    maxHp: 1500,
  });

  for (let i = 0; i < 5; i++) {
    createUnit({
      playerId: id,
      type: 'worker',
      x: baseX + randomInRange(-30, 30),
      y: baseY + randomInRange(-30, 30),
      hp: 100,
      maxHp: 100,
      speed: 1.4,
      attack: 4,
      range: 20,
      attackCooldown: 1200,
      currentTargetId: null,
      targetPos: null,
      action: 'idle',
    });
  }

  player.baseBuildingId = townHall.id;
  sendStateToPlayer(player);
  broadcastState();
  return player;
}

function removePlayer(playerId) {
  const player = game.players.get(playerId);
  if (!player) return;
  player.connected = false;
  game.players.delete(playerId);

  for (const [id, unit] of game.units) {
    if (unit.playerId === playerId) game.units.delete(id);
  }
  for (const [id, building] of game.buildings) {
    if (building.playerId === playerId) game.buildings.delete(id);
  }
  broadcastState();
}

function createUnit(data) {
  const id = String(nextUnitId++);
  const unit = {
    id,
    playerId: data.playerId,
    type: data.type || 'soldier',
    x: data.x || 0,
    y: data.y || 0,
    hp: data.hp || 100,
    maxHp: data.maxHp || 100,
    speed: data.speed || 1.2,
    attack: data.attack || 10,
    range: data.range || 25,
    attackCooldown: data.attackCooldown || 1000,
    lastAttackAt: 0,
    currentTargetId: null,
    targetPos: null,
    action: data.action || 'idle',
  };
  game.units.set(id, unit);
  return unit;
}

function createBuilding(data) {
  const id = String(nextBuildingId++);
  const building = {
    id,
    playerId: data.playerId,
    type: data.type || 'barracks',
    x: data.x || 0,
    y: data.y || 0,
    hp: data.hp || 300,
    maxHp: data.maxHp || 300,
    queue: [],
  };
  game.buildings.set(id, building);
  return building;
}

function serializeGameState() {
  return {
    serverTime: Date.now(),
    players: [...game.players.values()].map(p => ({
      id: p.id,
      name: p.name,
      resources: p.resources,
      color: p.color,
      connected: p.connected,
      baseBuildingId: p.baseBuildingId || null,
    })),
    units: [...game.units.values()].map(u => ({
      id: u.id,
      playerId: u.playerId,
      type: u.type,
      x: u.x,
      y: u.y,
      hp: u.hp,
      maxHp: u.maxHp,
      action: u.action,
      targetPos: u.targetPos,
      currentTargetId: u.currentTargetId,
    })),
    buildings: [...game.buildings.values()].map(b => ({
      id: b.id,
      playerId: b.playerId,
      type: b.type,
      x: b.x,
      y: b.y,
      hp: b.hp,
      maxHp: b.maxHp,
      queue: b.queue,
    })),
  };
}

function sendStateToPlayer(player) {
  if (!player || !player.ws || player.ws.readyState !== WebSocket.OPEN) return;
  player.ws.send(JSON.stringify({
    type: 'state',
    data: serializeGameState(),
  }));
}

function broadcastState() {
  const payload = JSON.stringify({
    type: 'state',
    data: serializeGameState(),
  });
  for (const player of game.players.values()) {
    if (player.ws && player.ws.readyState === WebSocket.OPEN) {
      player.ws.send(payload);
    }
  }
}

function getEntityById(id) {
  return game.units.get(String(id)) || game.buildings.get(String(id)) || null;
}

function handleBuild(player, msg) {
  const type = String(msg.typeName || msg.buildingType || 'barracks');
  const costMap = { barracks: 150, turret: 200, wall: 50 };
  const cost = costMap[type] ?? 150;

  if (player.resources < cost) {
    return sendError(player, 'insufficient_resources');
  }

  const x = Number(msg.x);
  const y = Number(msg.y);

  if (!Number.isFinite(x) || !Number.isFinite(y)) {
    return sendError(player, 'invalid_position');
  }

  player.resources -= cost;
  createBuilding({
    playerId: player.id,
    type,
    x: clamp(x, 0, 2000),
    y: clamp(y, 0, 2000),
    hp: type === 'wall' ? 400 : 300,
    maxHp: type === 'wall' ? 400 : 300,
  });
  broadcastState();
}

function handleMove(player, msg) {
  const unitIds = Array.isArray(msg.unitIds) ? msg.unitIds : [msg.unitId].filter(Boolean);
  const x = Number(msg.x);
  const y = Number(msg.y);

  if (!unitIds.length || !Number.isFinite(x) || !Number.isFinite(y)) {
    return sendError(player, 'invalid_move');
  }

  for (const uid of unitIds) {
    const unit = game.units.get(String(uid));
    if (!unit || unit.playerId !== player.id) continue;
    unit.targetPos = { x: clamp(x, 0, 2000), y: clamp(y, 0, 2000) };
    unit.currentTargetId = null;
    unit.action = 'moving';
  }
  broadcastState();
}

function handleAttack(player, msg) {
  const unitIds = Array.isArray(msg.unitIds) ? msg.unitIds : [msg.unitId].filter(Boolean);
  const targetId = String(msg.targetId || '');
  const target = getEntityById(targetId);

  if (!unitIds.length || !target) {
    return sendError(player, 'invalid_attack');
  }

  for (const uid of unitIds) {
    const unit = game.units.get(String(uid));
    if (!unit || unit.playerId !== player.id) continue;
    unit.currentTargetId = targetId;
    unit.targetPos = null;
    unit.action = 'attacking';
  }
  broadcastState();
}

function handleSpawn(player, msg) {
  const type = String(msg.unitType || 'soldier');
  const costMap = { worker: 50, soldier: 100, archer: 120 };
  const stats = {
    worker: { hp: 100, maxHp: 100, speed: 1.4, attack: 4, range: 18, attackCooldown: 1200 },
    soldier: { hp: 120, maxHp: 120, speed: 1.1, attack: 14, range: 24, attackCooldown: 900 },
    archer: { hp: 80, maxHp: 80, speed: 1.2, attack: 10, range: 140, attackCooldown: 1100 },
  }[type] || { hp: 120, maxHp: 120, speed: 1.1, attack: 14, range: 24, attackCooldown: 900 };

  const cost = costMap[type] ?? 100;
  if (player.resources < cost) return sendError(player, 'insufficient_resources');

  const x = Number(msg.x);
  const y = Number(msg.y);
  if (!Number.isFinite(x) || !Number.isFinite(y)) return sendError(player, 'invalid_spawn');

  player.resources -= cost;
  createUnit({
    playerId: player.id,
    type,
    x: clamp(x, 0, 2000),
    y: clamp(y, 0, 2000),
    ...stats,
  });
  broadcastState();
}

function sendError(player, error) {
  if (player.ws && player.ws.readyState === WebSocket.OPEN) {
    player.ws.send(JSON.stringify({ type: 'error', error }));
  }
}

function processCommand(player, msg) {
  if (!msg || typeof msg !== 'object') return sendError(player, 'invalid_message');

  const cmd = String(msg.command || msg.type || '').toLowerCase();

  switch (cmd) {
    case 'build':
      return handleBuild(player, msg);
    case 'move':
      return handleMove(player, msg);
    case 'attack':
      return handleAttack(player, msg);
    case 'spawn':
      return handleSpawn(player, msg);
    case 'ping':
      if (player.ws && player.ws.readyState === WebSocket.OPEN) {
        player.ws.send(JSON.stringify({ type: 'pong', serverTime: Date.now() }));
      }
      return;
    case 'name':
      if (typeof msg.name === 'string' && msg.name.trim()) {
        player.name = msg.name.trim().slice(0, 24);
        broadcastState();
      }
      return;
    default:
      return sendError(player, 'unknown_command');
  }
}

function updateUnits() {
  const now = Date.now();

  for (const unit of game.units.values()) {
    if (unit.targetPos) {
      const dx = unit.targetPos.x - unit.x;
      const dy = unit.targetPos.y - unit.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 1) {
        unit.x = unit.targetPos.x;
        unit.y = unit.targetPos.y;
        unit.targetPos = null;
        unit.action = 'idle';
      } else {
        const step = unit.speed * 2;
        unit.x += (dx / dist) * Math.min(step, dist);
        unit.y += (dy / dist) * Math.min(step, dist);
      }
    }

    if (unit.currentTargetId) {
      const target = getEntityById(unit.currentTargetId);
      if (!target || target.hp <= 0) {
        unit.currentTargetId = null;
        unit.action = unit.targetPos ? 'moving' : 'idle';
        continue;
      }

      const d = distance(unit, target);
      if (d <= unit.range) {
        if (now - unit.lastAttackAt >= unit.attackCooldown) {
          unit.lastAttackAt = now;
          target.hp -= unit.attack;
          if (target.hp <= 0) {
            if (game.units.has(target.id)) game.units.delete(target.id);
            if (game.buildings.has(target.id)) game.buildings.delete(target.id);
            unit.currentTargetId = null;
            unit.action = 'idle';
          }
        }
      } else {
        unit.targetPos = { x: target.x, y: target.y };
        unit.action = 'moving';
      }
    }
  }
}

setInterval(() => {
  updateUnits();
}, TICK_MS);

setInterval(() => {
  broadcastState();
}, 250);

wss.on('connection', (ws) => {
  const player = createPlayer(ws);

  ws.on('message', (data) => {
    player.lastSeen = Date.now();
    let msg = null;
    try {
      msg = JSON.parse(data.toString());
    } catch (e) {
      return sendError(player, 'invalid_json');
    }
    processCommand(player, msg);
  });

  ws.on('close', () => {
    removePlayer(player.id);
  });

  ws.on('error', () => {
    removePlayer(player.id);
  });

  if (ws.readyState === WebSocket.OPEN) {
    ws.send(JSON.stringify({
      type: 'welcome',
      playerId: player.id,
      serverTime: Date.now(),
    }));
  }
});

